import{_ as s,c as a,o as n,U as e}from"./chunks/framework.9QHaLlVJ.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/数据库/Mysql/问题/连接断开导致XA事务丢失.md","filePath":"packages/doc/src/数据库/Mysql/问题/连接断开导致XA事务丢失.md","lastUpdated":1702458087000}'),p={name:"doc/数据库/Mysql/问题/连接断开导致XA事务丢失.md"},l=e(`<p>我们看到在MySQL 5.7版本里大量遗留很多年的bug都被fix掉了，bug#12161就是其中一个，该bug在2005年第一次report到Bug list上，十年之后终于在MySQL 5.7.7 第一个RC版本被fix了。</p><h2 id="bug描述" tabindex="-1">Bug描述 <a class="header-anchor" href="#bug描述" aria-label="Permalink to &quot;Bug描述&quot;">​</a></h2><p>当我们显式开启一个XA事务，执行操作，并完成XA PREPARE后，如果Kill session或者主动断开再重连执行XA RECOVER，之前的这个XA事务就会直接丢失掉了。</p><p>例如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; XA BEGIN &#39;abc&#39;;</span></span>
<span class="line"><span>Query OK, 0 rows affected (0.00 sec)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>mysql&gt; INSERT INTO t1 VALUES (1,2,3);</span></span>
<span class="line"><span>Query OK, 1 row affected (0.00 sec)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>mysql&gt; XA END &#39;abc&#39;;</span></span>
<span class="line"><span>Query OK, 0 rows affected (0.00 sec)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>mysql&gt; XA PREPARE &#39;abc&#39;;</span></span>
<span class="line"><span>Query OK, 0 rows affected (0.00 sec)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>mysql&gt; Ctrl-C -- exit!</span></span>
<span class="line"><span>Aborted</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>mysql&gt; XA RECOVER;</span></span>
<span class="line"><span>Empty set (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>有趣的是，如果在XA PREPARE后把实例KILL掉，是可以通过XA RECOVER恢复的：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; XA RECOVER;</span></span>
<span class="line"><span>+----------+--------------+--------------+------+</span></span>
<span class="line"><span>| formatID | gtrid_length | bqual_length | data |</span></span>
<span class="line"><span>+----------+--------------+--------------+------+</span></span>
<span class="line"><span>| 1 | 3 | 0 | abc |</span></span>
<span class="line"><span>+----------+--------------+--------------+------+</span></span>
<span class="line"><span>1 row in set (0.00 sec)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>mysql&gt; XA COMMIT &#39;abc&#39;;</span></span>
<span class="line"><span>Query OK, 0 rows affected (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>虽然实例异常重启可以恢复事务，但引入的另外一个问题是：事务变更的binlog丢失，导致主备数据不一致。</p><p>bug产生的原因也很简单：在退出session时，线程总是会去无条件的回滚掉自己尚未提交的事务。</p><h2 id="官方修复" tabindex="-1">官方修复 <a class="header-anchor" href="#官方修复" aria-label="Permalink to &quot;官方修复&quot;">​</a></h2><h3 id="持久化" tabindex="-1">持久化 <a class="header-anchor" href="#持久化" aria-label="Permalink to &quot;持久化&quot;">​</a></h3><p>为了解决这个问题，将XA的两阶段记录到了Binlog中；</p><p>对于上文描述的序列，当执行到XA PREPARE时，记录第一阶段的binlog，如下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Query event : XA START X&#39;616263&#39;,X&#39;’,1  // 这里的&#39;616262&#39;即是&#39;abc&#39;的十六进制编码</span></span>
<span class="line"><span>Table_map event</span></span>
<span class="line"><span>Write_rows event</span></span>
<span class="line"><span>Query event：XA END X&#39;616263&#39;,X&#39;&#39;,1</span></span>
<span class="line"><span>XA_prepare event： XA PREPARE X&#39;616263&#39;,X&#39;’,1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这时候该XA事务同时在InnoDB层（事务处于Prepare状态，Redo持久化到磁盘）和Server层都有持久化信息。</p><p>其中XA_PREPARE事件是新引入的事件类型（内部类为XA_prepare_event），以后版本升级需要注意到这个低版本不兼容事件。</p><p>然后再执行XA COMMIT ‘abc’，产生新的事件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Query event：XA COMMIT X&#39;616263&#39;,X&#39;&#39;,1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果执行XA ROLLBACK，则记录：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Query event：XA ROLLBACK X&#39;616263&#39;,X&#39;&#39;,1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>由于XA PREPARE和XA COMMIT是分开执行的，因此在这两个事件中间可能存在别的事务，备库复制线程需要处理这种情况。</p><p>为了实现XA PREPARE写binlog，对binlog_prepare进行了扩展，这里会调用mysql_bin_log.commit， 将cache中的binlog刷到文件中。</p><p>Tips：XID可以包含三个部分：gtrid, [, bqual [, format ID]]，其中gtrid是必选的，表示全局标识，bqual是分支标识，默认为空’‘，format ID是一个unsigned整型，默认值为1，在上例中，我们只指定了gtrid为’abc’，因此bqual段和format ID均为默认值。更具体的描述参考<a href="http://dev.mysql.com/doc/refman/5.7/en/xa-statements.html" target="_blank" rel="noreferrer">官方文档</a>。</p><h3 id="如何恢复" tabindex="-1">如何恢复 <a class="header-anchor" href="#如何恢复" aria-label="Permalink to &quot;如何恢复&quot;">​</a></h3><p>当会话断开时（例如kill session或者一次干净的shutdown/restart操作），我们必须要能恢复该事务，之前的逻辑是在cleanup时，直接回滚所有的活跃事务。在新版本中，对XA PREPARE的事务做了特殊处理（THD::cleanup），如果处于Prepare状态，就将事务的in_recovery设置为TRUE，并更新到hash表transaction_cache中（transaction_cache_detach），该hash表用于维护所有XA事务。</p><p>对于非XA的活跃事务，在会话断开时，依然采用回滚策略。</p><p>当重连客户端后，我们可以直接执行 XA COMMIT ‘abc’，这时候会通过XID关键字去搜索transaction_cache并将对应的事务提交掉。</p><p>同时BINLOG的状态要保持一致，如果会话断开前的XA PREPARE没有记录Binlog， 重连后执行XA COMMIT也不应该记录。</p><h3 id="备库复制" tabindex="-1">备库复制 <a class="header-anchor" href="#备库复制" aria-label="Permalink to &quot;备库复制&quot;">​</a></h3><p>由于XA PREPARE和XA COMMIT是分开记录的，当碰到XA COMMIT时，备库采用等待之前的事务全部完成，然后再执行的方式（相当于退化到串行）。</p><p>另外，我们知道在一个正常的会话过程中，总是为其cache一个事务对象，新的事务会重用这个事务对象，避免多次分配；而XA事务的COMMIT和PREPARE是分离的，需要为XA事务单独分配事务对象。因此复制线程执行XA START时，将其拥有的事务对象临时保存起来（detach_native_trx），当执行到XA_prepare_log_event事件时，再将其恢复给复制线程，同时XA事务对象关闭read view，将is_recovered设置为TRUE（函数innodb_replace_trx_in_thd）。</p><p>随后复制线程在执行到XA COMMIT时直接根据XID找到对应的XA事务进行提交。</p><h2 id="参考" tabindex="-1">参考： <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考：&quot;">​</a></h2><p><a href="http://dev.mysql.com/worklog/task/?id=6860" target="_blank" rel="noreferrer">WL#6860</a> Binlogging XA-prepared transaction Github：git show f4c37f7aea732763947980600c6882ec908a54a0 MySQL 5.7.7-RC</p>`,34),r=[l];function i(t,c,b,o,d,u){return n(),a("div",null,r)}const g=s(p,[["render",i]]);export{m as __pageData,g as default};
